--
-- Name: v_event_manager_report _RETURN; Type: RULE; Schema: public; Owner: smeryse
--

CREATE OR REPLACE VIEW public.v_event_manager_report AS
 SELECT e.event_id,
    e.venue AS "Площадка",
    e.city AS "Город",
    e.date AS "Дата",
    e.event_type AS "Тип события",
    e.audience_size AS "Аудитория",
    c.name AS "Название сета",
    count(ct.track_id) AS "Треков в сете",
    round(((sum(t.duration))::numeric / 60.0), 2) AS "Длительность сета (мин)",
    round(avg(t.rating), 2) AS "Средний рейтинг треков",
    e.earnings AS "Доход ($)",
        CASE
            WHEN (e.audience_size >= 10000) THEN 'Крупное'::text
            WHEN (e.audience_size >= 1000) THEN 'Среднее'::text
            ELSE 'Небольшое'::text
        END AS "Масштаб"
   FROM (((public.event e
     LEFT JOIN public.collection c ON ((e.collection_id = c.collection_id)))
     LEFT JOIN public.collectiontrack ct ON ((c.collection_id = ct.collection_id)))
     LEFT JOIN public.track t ON ((ct.track_id = t.track_id)))
  GROUP BY e.event_id, c.collection_id
  ORDER BY e.date DESC;


--
-- Name: v_prepared_sets _RETURN; Type: RULE; Schema: public; Owner: smeryse
--

CREATE OR REPLACE VIEW public.v_prepared_sets AS
 SELECT c.collection_id,
    c.name AS set_name,
    c.type,
    c.style,
    c.planned_duration,
    array_agg(t.title ORDER BY ct."position") AS tracks,
    count(ct.track_id) AS total_tracks,
    sum(t.duration) AS actual_duration_seconds
   FROM ((public.collection c
     LEFT JOIN public.collectiontrack ct ON ((c.collection_id = ct.collection_id)))
     LEFT JOIN public.track t ON ((ct.track_id = t.track_id)))
  GROUP BY c.collection_id, c.name, c.type, c.style, c.planned_duration
  ORDER BY c.created_at DESC;


